// Provide deterministic draft and edited content for manual testing.
return [{
  json: {
    articleId: 'manual-ai-agent-001',
    sourceUrl: 'https://example.com/ai-agent',
    draft: {
      title: 'AI Agent 不只是生成文字',
      subtitle: '從工具呼叫到流程決策',
      summary: '本文拆解 AI Agent 在工作流中的真正角色。',
      markdown: '# AI Agent 不只是生成文字\n\n在這個快速變化的時代，AI Agent 正在重新定義工作流。\n\n## 真正的差別\n\n值得注意的是，它應該根據工具回傳的結果決定下一步。\n\n## 結論\n\n歡迎按讚、分享與留言。'
    },
    edited: {
      title: 'AI Agent 為什麼不能只會生成文字？',
      subtitle: '真正的差別，在於它能否根據工具結果做決策',
      summary: '本文從 n8n 工作流出發，拆解 AI Agent 的決策、工具使用與實作方式。',
      markdown: '# AI Agent 為什麼不能只會生成文字？\n\n如果一個 AI Agent 只會把提示詞變成文字，它其實還不算真正的 Agent。\n\n## 真正的差別\n\n關鍵不在生成，而在於它能否根據工具回傳結果決定下一步。\n\n## 結論\n\n如果你也在打造 AI Agent，歡迎交流你的做法。'
    },
    editor: 'human',
    editedAt: new Date().toISOString(),
    metrics: {
      views: 0,
      reads: 0,
      claps: 0,
      responses: 0
    }
  }
}];

// Normalize the feedback payload and validate required fields.
const input = $input.first().json;
const body = input.body ?? input;

if (!body.articleId) {
  throw new Error('articleId is required');
}
if (!body.draft?.markdown || !body.edited?.markdown) {
  throw new Error('draft.markdown and edited.markdown are required');
}

return [{
  json: {
    articleId: String(body.articleId),
    sourceUrl: String(body.sourceUrl ?? ''),
    draft: {
      title: String(body.draft.title ?? ''),
      subtitle: String(body.draft.subtitle ?? ''),
      summary: String(body.draft.summary ?? ''),
      markdown: String(body.draft.markdown)
    },
    edited: {
      title: String(body.edited.title ?? ''),
      subtitle: String(body.edited.subtitle ?? ''),
      summary: String(body.edited.summary ?? ''),
      markdown: String(body.edited.markdown)
    },
    editor: String(body.editor ?? 'human'),
    editedAt: String(body.editedAt ?? new Date().toISOString()),
    metrics: {
      views: Number(body.metrics?.views ?? 0),
      reads: Number(body.metrics?.reads ?? 0),
      claps: Number(body.metrics?.claps ?? 0),
      responses: Number(body.metrics?.responses ?? 0)
    }
  }
}];

// Compute a deterministic line-level diff without external packages.
const input = $input.first().json;

const splitLines = (text) => String(text)
  .replace(/\r\n/g, '\n')
  .split('\n')
  .map((line) => line.trimEnd());

const draftLines = splitLines(input.draft.markdown);
const editedLines = splitLines(input.edited.markdown);

const m = draftLines.length;
const n = editedLines.length;
const dp = Array.from({ length: m + 1 }, () => Array(n + 1).fill(0));

for (let i = m - 1; i >= 0; i--) {
  for (let j = n - 1; j >= 0; j--) {
    dp[i][j] = draftLines[i] === editedLines[j]
      ? dp[i + 1][j + 1] + 1
      : Math.max(dp[i + 1][j], dp[i][j + 1]);
  }
}

const changes = [];
let i = 0;
let j = 0;

while (i < m && j < n) {
  if (draftLines[i] === editedLines[j]) {
    i++;
    j++;
    continue;
  }

  if (dp[i + 1][j] >= dp[i][j + 1]) {
    changes.push({
      type: 'removed',
      before: draftLines[i],
      after: ''
    });
    i++;
  } else {
    changes.push({
      type: 'added',
      before: '',
      after: editedLines[j]
    });
    j++;
  }
}

while (i < m) {
  changes.push({ type: 'removed', before: draftLines[i], after: '' });
  i++;
}

while (j < n) {
  changes.push({ type: 'added', before: '', after: editedLines[j] });
  j++;
}

const paired = [];
for (let index = 0; index < changes.length; index++) {
  const current = changes[index];
  const next = changes[index + 1];

  if (current?.type === 'removed' && next?.type === 'added') {
    paired.push({
      type: 'replaced',
      before: current.before,
      after: next.after
    });
    index++;
  } else {
    paired.push(current);
  }
}

const titleChanged = input.draft.title !== input.edited.title;
const subtitleChanged = input.draft.subtitle !== input.edited.subtitle;
const summaryChanged = input.draft.summary !== input.edited.summary;

const removedCount = paired.filter((item) => item.type === 'removed').length;
const addedCount = paired.filter((item) => item.type === 'added').length;
const replacedCount = paired.filter((item) => item.type === 'replaced').length;

const draftLength = input.draft.markdown.length;
const editedLength = input.edited.markdown.length;
const lengthDelta = editedLength - draftLength;
const lengthDeltaRatio = draftLength ? lengthDelta / draftLength : 0;

return [{
  json: {
    ...input,
    diff: {
      titleChanged,
      subtitleChanged,
      summaryChanged,
      titleBefore: input.draft.title,
      titleAfter: input.edited.title,
      subtitleBefore: input.draft.subtitle,
      subtitleAfter: input.edited.subtitle,
      summaryBefore: input.draft.summary,
      summaryAfter: input.edited.summary,
      changes: paired.filter((item) => item.before || item.after),
      stats: {
        removedCount,
        addedCount,
        replacedCount,
        totalChanges: removedCount + addedCount + replacedCount,
        draftLength,
        editedLength,
        lengthDelta,
        lengthDeltaRatio
      }
    }
  }
}];

// Convert the raw diff into a standard feedback contract for the Learning Agent.
const input = $input.first().json;
const meaningfulChanges = input.diff.changes
  .filter((change) => {
    const before = String(change.before ?? '').trim();
    const after = String(change.after ?? '').trim();
    return before.length >= 6 || after.length >= 6;
  })
  .slice(0, 50);

const feedbackId = `feedback:${input.articleId}:${Date.now()}`;

return [{
  json: {
    feedbackId,
    articleId: input.articleId,
    sourceUrl: input.sourceUrl,
    editor: input.editor,
    editedAt: input.editedAt,
    originalDraft: input.draft,
    finalVersion: input.edited,
    editorialDiff: {
      titleChanged: input.diff.titleChanged,
      subtitleChanged: input.diff.subtitleChanged,
      summaryChanged: input.diff.summaryChanged,
      titleBefore: input.diff.titleBefore,
      titleAfter: input.diff.titleAfter,
      subtitleBefore: input.diff.subtitleBefore,
      subtitleAfter: input.diff.subtitleAfter,
      summaryBefore: input.diff.summaryBefore,
      summaryAfter: input.diff.summaryAfter,
      changes: meaningfulChanges,
      stats: input.diff.stats
    },
    metrics: input.metrics,
    metadata: {
      workflow: '09-feedback-collector',
      version: '0.9.0',
      status: 'feedback_collected',
      collectedAt: new Date().toISOString()
    }
  }
}];
